import React, { useState } from 'react';
import './LoginForm.css';
import { FaUser, FaLock } from "react-icons/fa";

const LoginForm = () => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [isRegistering, setIsRegistering] = useState(false); 

  // 1. Beni Hatırla kutucuğu için yeni state ekledik (Varsayılan: seçili değil)
  const [rememberMe, setRememberMe] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (isRegistering) {
        // --- REGISTER (KAYIT OL) İŞLEMLERİ ---
        try {
            const response = await fetch('http://localhost:5001/api/auth/register', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ email, password }), 
            });

            const data = await response.json();

            if (response.ok) {
                alert("Kayıt Başarılı! Şimdi giriş yapabilirsiniz.");
                setIsRegistering(false); // Başarılı olunca login ekranına at
                setPassword(''); // Şifre kutusunu temizle
            } else {
                alert("Hata: " + data.message);
            }
        } catch (error) {
            console.error("Bağlantı hatası:", error);
            alert("Sunucuya bağlanılamadı.");
        }
    } else {
        // --- LOGIN (GİRİŞ YAP) İŞLEMLERİ ---
        try {
            const response = await fetch('http://localhost:5001/api/auth/login', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                // 2. Email ve şifrenin yanına 'rememberMe' bilgisini de backend'e yolluyoruz
                body: JSON.stringify({ email, password, rememberMe }), 
            });

            const data = await response.json();

            if (response.ok) {
                alert("Giriş Başarılı kral!\nTarayıcı konsoluna bakarak token'ı görebilirsin.");
                console.log("Sana Özel VIP Bileklik (JWT):", data.token);

                // 3. BENİ HATIRLA MANTIĞI BURADA ÇALIŞIYOR
                if (rememberMe) {
                    localStorage.setItem('token', data.token); // Kalıcı hafızaya kaydet
                } else {
                    sessionStorage.setItem('token', data.token); // Geçici hafızaya kaydet
                }

                // İleride buraya: Giriş başarılıysa ana sayfaya yönlendirme kodu yazılır (örn: navigate('/home'))

            } else {
                alert("Hata: " + data.message); // Örn: "Hatalı şifre" veya "Kullanıcı bulunamadı"
            }
        } catch (error) {
            console.error("Bağlantı hatası:", error);
            alert("Sunucuya bağlanılamadı.");
        }
    }
  };

  return (
    <div className='wrapper'> 
      <form onSubmit={handleSubmit}>
        <h1>{isRegistering ? "Register" : "Login"}</h1>

        <div className="input-box">
            <input 
              type="email" 
              placeholder='E-Mail' 
              required 
              value={email} 
              onChange={(e) => setEmail(e.target.value)} 
            />
            <FaUser className='icon' />
        </div>

        <div className="input-box">
            <input 
              type="password" 
              placeholder='Password' 
              required 
              value={password} 
              onChange={(e) => setPassword(e.target.value)} 
            />
            <FaLock className='icon' />
        </div>

        {!isRegistering && (
            <div className="remember-forgot">
                <label>
                    <input 
                        type="checkbox" 
                        checked={rememberMe} // 4. Kutucuğu state'e bağladık
                        onChange={(e) => setRememberMe(e.target.checked)} // Tıklanınca state güncellenir
                    />
                    Remember me
                </label>
                <a href="#">Forgot Password?</a>
            </div>
        )}

        <button type="submit">{isRegistering ? "REGISTER" : "LOGIN"}</button>

        <div className="register-link">
            <p>
                {isRegistering ? "Already have an account? " : "Don't Have an Account? "}
                <a href="#" onClick={(e) => {
                    e.preventDefault();
                    setIsRegistering(!isRegistering);
                }}>
                    {isRegistering ? "Login" : "Register"}
                </a>
            </p>
        </div>
      </form>
    </div>
  );
};

export default LoginForm;
